const { gql, ApolloServer, AuthenticationError } = require('apollo-server-express');
const { v4: uuidv4 } = require('uuid');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const { Pool } = require('pg');

const pool = new Pool({
  user: process.env.DB_USER,
  host: process.env.DB_HOST,
  database: process.env.DB_NAME,
  password: process.env.DB_PASSWORD,
  port: process.env.DB_PORT,
});

const typeDefs = gql`
  type Invoice {
    id: ID!
    invoiceNumber: String!
    customerId: ID!
    customerName: String!
    amount: Float!
    status: String!
    createdAt: String!
    updatedAt: String!
    items: [InvoiceItem!]!
  }

  type InvoiceItem {
    id: ID!
    description: String!
    quantity: Int!
    unitPrice: Float!
    total: Float!
  }

  type Query {
    invoice(id: ID!): Invoice
  }
`;

const resolvers = {
  Query: {
    invoice: async (parent, args, context) => {
      const { id } = args;
      const { userId } = context;

      // Validate input
      if (!id || typeof id !== 'string' || id.trim() === '') {
        throw new Error('Invalid invoice ID');
      }

      try {
        // Use parameterized query to prevent SQL injection
        const query = `
          SELECT 
            i.id,
            i.invoice_number,
            i.customer_id,
            i.customer_name,
            i.amount,
            i.status,
            i.created_at,
            i.updated_at,
            json_agg(
              json_build_object(
                'id', ii.id,
                'description', ii.description,
                'quantity', ii.quantity,
                'unitPrice', ii.unit_price,
                'total', ii.total
              )
            ) as items
          FROM invoices i
          LEFT JOIN invoice_items ii ON i.id = ii.invoice_id
          WHERE i.id = $1 AND i.customer_id = $2
          GROUP BY i.id
          LIMIT 1
        `;

        const result = await pool.query(query, [id, userId]);
        
        if (result.rows.length === 0) {
          return null;
        }

        const invoice = result.rows[0];
        
        // Ensure items is always an array
        if (!invoice.items || invoice.items === 'null') {
          invoice.items = [];
        } else {
          invoice.items = JSON.parse(invoice.items);
        }

        return {
          id: invoice.id,
          invoiceNumber: invoice.invoice_number,
          customerId: invoice.customer_id,
          customerName: invoice.customer_name,
          amount: parseFloat(invoice.amount),
          status: invoice.status,
          createdAt: invoice.created_at.toISOString(),
          updatedAt: invoice.updated_at.toISOString(),
          items: invoice.items
        };
      } catch (error) {
        console.error('Database error:', error);
        throw new Error('Failed to fetch invoice');
      }
    }
  }
};

module.exports = { typeDefs, resolvers };